import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { FaSearch } from 'react-icons/fa';

export default function Navbar() {
    const { user, logout } = useAuth();
    const navigate = useNavigate();
    const [searchQuery, setSearchQuery] = useState('');

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchQuery.trim()) {
            navigate(`/?search=${searchQuery}`);
        }
    };

    return (
        <nav className="fixed top-0 left-0 right-0 bg-gray-900 border-b border-gray-800 z-50">
            <div className="flex items-center justify-between px-4 py-3">
                <Link to="/" className="flex items-center gap-2">
                    <div className="figma-logo" style={{ position: 'relative', top: 0, left: 0 }}>
                        <img src="/images/figma-images/vector-5.svg" alt="logo" className="w-6 h-6 mx-auto mt-2" />
                    </div>
                    <span className="text-xl font-bold bg-gradient-to-r from-purple-500 to-pink-500 bg-clip-text text-transparent hidden sm:inline">
                        VideoHub
                    </span>
                </Link>

                <form onSubmit={handleSearch} className="flex-1 max-w-2xl mx-4">
                    <div className="relative">
                        <input
                            type="text"
                            placeholder="Поиск..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="figma-input pl-10"
                        />
                        <FaSearch className="absolute left-3 top-3 text-gray-400" />
                    </div>
                </form>

                <div className="flex items-center space-x-4">
                    {user ? (
                        <div className="relative group">
                            <div className="figma-avatar">
                                {user.username?.[0]?.toUpperCase()}
                            </div>
                            <div className="absolute right-0 mt-2 w-48 bg-gray-800 rounded-lg shadow-lg hidden group-hover:block">
                                <Link to={`/profile/${user.username}`} className="block px-4 py-2 hover:bg-gray-700">Профиль</Link>
                                <Link to="/upload" className="block px-4 py-2 hover:bg-gray-700">Загрузить видео</Link>
                                <button onClick={logout} className="block w-full text-left px-4 py-2 hover:bg-gray-700 text-red-400">
                                    Выйти
                                </button>
                            </div>
                        </div>
                    ) : (
                        <Link to="/login" className="figma-register-btn" style={{ position: 'relative', top: 0, right: 0 }}>
                            <span>Регистрация</span>
                            <img src="/images/figma-images/vector-18.svg" alt="user" width="16" height="16" />
                        </Link>
                    )}
                </div>
            </div>
        </nav>
    );
}
